/* 伪代码：四层功耗决策树 */
struct power_budget {
    uint32_t silicon_uaw;
    uint32_t board_uaw;
    uint32_t fw_active_uaw;
    float duty_cycle;
};

void evaluate_power_layers(struct power_budget *b) {
    if (b->silicon_uaw > 20) {
        log_warn("M4+ above, static high");
    }
    if (b->board_uaw > b->silicon_uaw * 2) {
        log_error("LDO static > chip 2x");
    }
    uint32_t avg = b->fw_active_uaw * b->duty_cycle;
    log_info("avg power %lu uA", avg);
}

/* 进入 STOP 模式的正确流程 */
void enter_stop_mode(void) {
    /* 1. 降电压标度到 Range 2 */
    HAL_PWREx_ControlVoltageScaling(
        PWR_REGULATOR_VOLTAGE_SCALE2
    );
    /* 2. 配置 RTC 闹钟中断为唤醒源 */
    __HAL_RTC_ALARM_ENABLE_IT(&hrtc, RTC_IT_ALRA);
    /* 3. 使能 PWR CLK */
    __HAL_RCC_PWR_CLK_ENABLE();
    /* 4. 清除 wakeup 标志 */
    __HAL_PWR_CLEAR_FLAG(PWR_FLAG_WU);
    /* 5. 设置 EXTI Line22 为中断模式 */
    HAL_NVIC_SetPriority(RTC_WKUP_IRQn, 2, 0);
    HAL_NVIC_EnableIRQ(RTC_WKUP_IRQn);
    /* 6. 进入 STOP 模式 */
    HAL_PWR_EnterSTOPMode(
        PWR_LOWPOWERREGULATOR_ON,
        PWR_STOPENTRY_WFE
    );
    /* 唤醒后从这里继续执行 */
    /* 7. 恢复电压标度 */
    HAL_PWREx_ControlVoltageScaling(
        PWR_REGULATOR_VOLTAGE_SCALE1
    );
    /* 8. 重新配置系统时钟 */
    SystemClock_Config();
}

/* 正确配置 GPIO 为模拟模式以降低泄漏 */
void configure_unused_gpios(void) {
    GPIO_InitTypeDef gpio = {0};
    gpio.Mode = GPIO_MODE_ANALOG;
    gpio.Pull = GPIO_NOPULL;
    gpio.Pin = GPIO_PIN_0 | GPIO_PIN_1 |
               GPIO_PIN_2 | GPIO_PIN_3 |
               GPIO_PIN_4 | GPIO_PIN_5 |
               GPIO_PIN_6 | GPIO_PIN_7;
    HAL_GPIO_Init(GPIOB, &gpio);
    /* 关闭未使用的时钟域 */
    __HAL_RCC_CRC_CLK_DISABLE();
    __HAL_RCC_BKP_RAM_CLK_DISABLE();
}

/* 重构前：忙等待轮询，功耗 800uA */
while (1) {
    HAL_ADC_Start(&hadc1);
    HAL_ADC_PollForConversion(&hadc1, 10);
    temp = HAL_ADC_GetValue(&hadc1);
    process_temperature(temp);
    HAL_Delay(10);
}

/* 重构后：中断+DMA 事件驱动，功耗 15uA */
volatile bool new_data_ready = false;
uint16_t adc_buf[2];
uint8_t buf_idx = 0;

void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef *h) {
    adc_buf[buf_idx] = HAL_ADC_GetValue(h);
    buf_idx = !buf_idx;
    new_data_ready = true;
}

int main(void) {
    HAL_ADC_Start_DMA(&hadc1, adc_buf, 2);
    while (1) {
        if (new_data_ready) {
            new_data_ready = false;
            process_temperature(adc_buf[!buf_idx]);
        }
        __HAL_RCC_PWR_CLK_ENABLE();
        HAL_PWR_EnterSTOPMode(
            PWR_LOWPOWERREGULATOR_ON,
            PWR_STOPENTRY_WFI
        );
        SystemClock_Config();
    }
}
